#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long x1,y1,x2,y2; scanf("%lld %lld %lld %lld",&x1,&y1,&x2,&y2);
        long long d1 = x1*x1 + y1*y1;
        long long d2 = x2*x2 + y2*y2;
        if(d1> d2) printf("ALEX\n");
        else if(d2> d1) printf("BOB\n");
        else printf("EQUAL\n");
    }
    return 0;
}

