            long d2 = x2*x2 + y2*y2;
            if(d1> d2) sb.append("ALEX\n");
            else if(d2> d1) sb.append("BOB\n");
            else sb.append("EQUAL\n");
        }
        System.out.print(sb.toString());
    }
}

