import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        x1 = int(next(it)); y1 = int(next(it)); x2 = int(next(it)); y2 = int(next(it))
        d1 = x1*x1 + y1*y1
        d2 = x2*x2 + y2*y2
        if d1 > d2:
            out.append('ALEX')
        elif d2 > d1:
            out.append('BOB')
        else:
            out.append('EQUAL')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

